// ============================================================================
// SEED EXECUTION
// ============================================================================

async function postEvent(event) {
  try {
    const res = await fetch(`${API_BASE}/api/v1/onthisday`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(event)
    });
    if (!res.ok) {
      const err = await res.text();
      console.error(`  ✗ ${event.year || ''} ${event.title}: ${res.status} - ${err.slice(0, 100)}`);
      return false;
    }
    const data = await res.json();
    return data.success;
  } catch (e) {
    console.error(`  ✗ ${event.title}: ${e.message}`);
    return false;
  }
}

async function main() {
  console.log(`\n📅 Seeding comprehensive On This Day dataset to ${API_BASE}\n`);

  // Add category-derived user_intents and search_keywords to each event
  function enhance(e) {
    const cat = CATEGORY_INTENTS[e.category] || CATEGORY_INTENTS.event;
    const enhanced = { ...e };
    // Combine our user_intents with the category's user_intents
    const baseUi = e.user_intents && e.user_intents.length > 0 ? e.user_intents : cat.user_intents;
    enhanced.user_intents = JSON.stringify(Array.from(new Set(baseUi)));
    // Add category SEO keywords to our keywords
    const baseSk = e.search_keywords && e.search_keywords.length > 0 ? e.search_keywords : [];
    enhanced.search_keywords = JSON.stringify(Array.from(new Set([...baseSk, ...cat.seo_keywords])));
    // Add country_name if country_code set
    if (e.country_name) delete enhanced.country_name;
    return enhanced;
  }

  // Enhance events
  const enhancedEvents = EVENTS.map(enhance);
  const enhancedCountries = COUNTRY_FOUNDING_EVENTS.map(enhance);

  console.log(`=== Seeding ${enhancedEvents.length} curated events ===`);
  let eventCount = 0;
  for (const e of enhancedEvents) {
    if (await postEvent(e)) {
      eventCount++;
      process.stdout.write('.');
    }
    await new Promise(r => setTimeout(r, 30));
  }
  console.log(`\n  ${eventCount}/${enhancedEvents.length} events seeded\n`);

  console.log(`=== Seeding ${enhancedCountries.length} country events ===`);
  let countryCount = 0;
  for (const e of enhancedCountries) {
    if (await postEvent(e)) {
      countryCount++;
      process.stdout.write('.');
    }
    await new Promise(r => setTimeout(r, 30));
  }
  console.log(`\n  ${countryCount}/${enhancedCountries.length} country events seeded\n`);

  console.log(`\n✅ Done! ${eventCount + countryCount} entries added.`);
  console.log(`\n📊 Data sources used:`);
  console.log(`   - Wikipedia (https://en.wikipedia.org) - primary content`);
  console.log(`   - Wikidata (https://www.wikidata.org) - structured data`);
  console.log(`   - Muffin Labs History API (https://history.muffinlabs.com/) - reference`);
  console.log(`   - Wikimedia Wikifeeds (https://api.wikimedia.org) - cross-reference`);
  console.log(`   - Nager.Date (https://date.nager.at) - public holidays (already integrated)`);
  console.log(`\n💡 To add more entries:`);
  console.log(`   1. Edit this file (EVENTS array)`);
  console.log(`   2. Run: node scripts/seed-onthisday-comprehensive.js`);
  console.log(`   3. Or fetch from APIs: curl https://history.muffinlabs.com/api/date/7/20`);
}

main().catch(console.error);
